// src/pages/admin/AdminLogin.js
import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { loginAdmin } from "../../services/adminApi";
import { useAuth } from "../../contexts/AuthContext";
import { TextField, Button, Typography, Box } from "@mui/material";

export default function AdminLogin() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [credentials, setCredentials] = useState({ username: "", password: "" });
  const [error, setError] = useState("");

  const handleChange = (e) => {
    setCredentials({ ...credentials, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await loginAdmin(credentials);
      if (res.data.success) {
        // Save token & role in context
        login({ token: res.data.token, role: res.data.role });
        localStorage.setItem("token", res.data.token); // ensure token is available for axios
        navigate("/admin/dashboard"); // redirect to dashboard
      } else {
        setError(res.data.message || "Login failed");
      }
    } catch (err) {
      console.error("Admin login error:", err);
      setError("Login failed. Check credentials or server.");
    }
  };

  return (
    <Box
      display="flex"
      flexDirection="column"
      alignItems="center"
      justifyContent="center"
      height="100vh"
    >
      <Typography variant="h4" gutterBottom>
        Admin Login
      </Typography>
      <form onSubmit={handleSubmit}>
        <TextField
          label="Username"
          name="username"
          value={credentials.username}
          onChange={handleChange}
          fullWidth
          margin="normal"
        />
        <TextField
          label="Password"
          name="password"
          type="password"
          value={credentials.password}
          onChange={handleChange}
          fullWidth
          margin="normal"
        />
        {error && (
          <Typography color="error" variant="body2" sx={{ mt: 1 }}>
            {error}
          </Typography>
        )}
        <Button type="submit" variant="contained" color="primary" sx={{ mt: 2 }} fullWidth>
          Login
        </Button>
      </form>
    </Box>
  );
}
